"use client"; import { useEffect, useState } from "react"; import AuthGuard from "@/components/AuthGuard"; import PageHeader from "@/components/PageHeader"; import DashboardShell from "@/components/DashboardShell"; import { cartApi, orderApi, CartItem } from "@/lib/api"; import { useRouter } from "next/navigation"; export default function CheckoutPage() { const router = useRouter(); const [items, setItems] = useState<CartItem[]>([]); const [form, setForm] = useState({ city: "", address: "", phone: "", notes: "" }); const [msg, setMsg] = useState(""); const [error, setError] = useState(""); useEffect(() => { cartApi.get().then((r) => setItems(r.items)); }, []); const place = async () => { setMsg(""); setError(""); try { await orderApi.place({ items: items.map(i => ({ productId: i.product._id, quantity: Number(i.quantity) })), shippingAddress: { city: form.city, address: form.address, phone: form.phone }, notes: form.notes }); setMsg("Order placed successfully"); setTimeout(() => router.push("/orders"), 800); } catch (e:any) { setError(e.message); } }; return <AuthGuard><PageHeader title="Checkout" text="Confirm shipping details and place your order." /><DashboardShell><div className="card card-pad">{msg && <div className="notice notice-ok">{msg}</div>}{error && <div className="notice notice-error">{error}</div>}{items.length === 0 ? <div className="empty">Cart is empty.</div> : <><div className="form-grid"><input className="input" placeholder="Shipping city" value={form.city} onChange={e=>setForm({ ...form, city: e.target.value })} /><input className="input" placeholder="Phone" value={form.phone} onChange={e=>setForm({ ...form, phone: e.target.value })} /></div><input className="input" style={{ marginTop: 14 }} placeholder="Shipping address" value={form.address} onChange={e=>setForm({ ...form, address: e.target.value })} /><textarea className="textarea" style={{ marginTop: 14 }} placeholder="Order notes" value={form.notes} onChange={e=>setForm({ ...form, notes: e.target.value })} /><button className="btn btn-primary" onClick={place}>Place order</button></>}</div></DashboardShell></AuthGuard>; }
